sql:
SELECT DISTINCT players.name
FROM players
JOIN player_statistics ON players.player_id = player_statistics.player_id;

SELECT AVG(kdr) AS average_kdr
FROM performance_metrics
WHERE player_id = (SELECT player_id FROM players WHERE name = 'John Doe');

SELECT DISTINCT p.name, p.role
FROM players p
JOIN matches m ON p.player_id = m.winner_id;

SELECT 
    (SELECT COUNT(*) FROM players) AS Total_Players, 
    (SELECT COUNT(*) FROM coaches) AS Total_Coaches;

SELECT DISTINCT name
FROM players
ORDER BY name ASC;
